 import { useState } from "react";
import { useParams } from "react-router-dom";

function PostDetails() {
  const { id } = useParams();

  const posts = [
    {
      id: 1,
      title: "MERN Stack Guide",
      image:
        "https://images.unsplash.com/photo-1516321318423-f06f85e504b3",
      content:
        "MERN Stack is a powerful technology stack consisting of MongoDB, Express.js, React.js and Node.js. It is widely used for building full-stack web applications.",
      likes: 12
    },
    {
      id: 2,
      title: "React Tutorial",
      image:
        "https://images.unsplash.com/photo-1633356122544-f134324a6cee",
      content:
        "React is a JavaScript library used for building modern user interfaces. Learn components, props, state, hooks and routing step by step.",
      likes: 8
    },
    {
      id: 3,
      title: "JavaScript Basics",
      image:
        "https://images.unsplash.com/photo-1515879218367-8466d910aaa4",
      content:
        "JavaScript is the programming language of the web. Learn variables, functions, loops, arrays, objects and DOM manipulation.",
      likes: 6
    }
  ];

  const post = posts.find((p) => p.id === Number(id));

  const [likes, setLikes] = useState(post?.likes || 0);

  const [comment, setComment] = useState("");

  const [comments, setComments] = useState([
    "Great article 👍",
    "Very helpful for beginners."
  ]);

  const handleLike = () => {
    setLikes(likes + 1);
  };

  const handleComment = () => {
    if (comment.trim() === "") return;

    setComments([...comments, comment]);
    setComment("");
  };

  if (!post) {
    return (
      <h2
        style={{
          textAlign: "center",
          marginTop: "50px"
        }}
      >
        Post Not Found
      </h2>
    );
  }

  return (
    <div
      style={{
        width: "80%",
        margin: "40px auto"
      }}
    >
      <img
        src={post.image}
        alt={post.title}
        style={{
          width: "100%",
          borderRadius: "20px",
          maxHeight: "500px",
          objectFit: "cover"
        }}
      />

      <h1
        style={{
          marginTop: "25px"
        }}
      >
        {post.title}
      </h1>

      <div
        style={{
          display: "flex",
          gap: "20px",
          marginTop: "15px",
          fontSize: "18px"
        }}
      >
        <span>❤️ {likes}</span>

        <button
          onClick={handleLike}
          style={{
            padding: "8px 16px",
            border: "none",
            borderRadius: "8px",
            background: "#6c4df6",
            color: "white",
            cursor: "pointer"
          }}
        >
          Like Post
        </button>
      </div>

      <p
        style={{
          marginTop: "25px",
          lineHeight: "1.8",
          fontSize: "18px"
        }}
      >
        {post.content}
      </p>

      <h2
        style={{
          marginTop: "50px"
        }}
      >
        Comments ({comments.length})
      </h2>

      {comments.map((item, index) => (
        <div
          key={index}
          className="comment-box"
        >
          {item}
        </div>
      ))}

      <textarea
        rows="4"
        placeholder="Add your comment..."
        value={comment}
        onChange={(e) =>
          setComment(e.target.value)
        }
        style={{
          width: "100%",
          padding: "15px",
          marginTop: "20px",
          borderRadius: "10px"
        }}
      />

      <button
        onClick={handleComment}
        style={{
          marginTop: "15px",
          padding: "12px 20px",
          border: "none",
          borderRadius: "10px",
          background: "#6c4df6",
          color: "white",
          cursor: "pointer"
        }}
      >
        Submit Comment
      </button>
    </div>
  );
}

export default PostDetails;
